fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n < 3 {
        return 0;
    }

    // Determine the set S of indices chosen for peaks: {1, 3, 5, ...}
    // This set maximizes the number of non-adjacent peaks possible.
    let mut is_peak_candidate = vec![false; n];
    for i in (1..n - 1).step_by(2) {
        is_peak_candidate[i] = true;
    }

    // 1. Forward Pass (L): Calculate minimum required height based on left neighbors
    let mut l = nums.clone();
    for i in 1..n {
        // L[i] must be at least nums[i]
        // If i is a candidate peak, it must be strictly greater than L[i-1]
        if is_peak_candidate[i] {
            l[i] = l[i].max(l[i - 1] + 1);
        }
    }

    // 2. Backward Pass (R): Calculate minimum required height based on right neighbors
    let mut r = nums.clone();
    for i in (0..n - 1).rev() {
        // R[i] must be at least nums[i]
        // If i is a candidate peak, it must be strictly greater than R[i+1]
        if is_peak_candidate[i] {
            r[i] = r[i].max(r[i + 1] + 1);
        }
    }

    // 3. Calculate Total Cost
    let mut total_cost: i64 = 0;
    for i in 0..n {
        // The final required height B[i] must satisfy both left and right constraints
        let b_i = l[i].max(r[i]);

        // Since l[i] and r[i] are derived from nums[i] and only increase, b_i >= nums[i]
        total_cost += b_i - nums[i];
    }

    total_cost
}
