fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n < 3 {
        return 0;
    }

    // We aim to maximize the number of peaks, which requires choosing non-adjacent indices.
    // The maximum density is achieved by selecting indices 1, 3, 5, ... (Sequence A) 
    // or 2, 4, 6, ... (Sequence B). 
    // We calculate the minimum cost for achieving maximum peaks in both scenarios 
    // and return the smaller cost.

    // Since peaks must be non-adjacent, the cost contributions for each potential peak 
    // are independent if we only increase the peak value itself.

    // Calculate cost for Sequence A: {1, 3, 5, ...}
    let mut cost_a: i64 = 0;
    let mut i = 1;
    while i <= n - 2 {
        // Required value R_i must be strictly greater than both neighbors.
        // R_i = max(nums[i-1], nums[i+1]) + 1
        let neighbors_max = nums[i - 1].max(nums[i + 1]);
        let required_value = neighbors_max + 1;

        // Cost is the difference if the current value is insufficient, otherwise 0.
        let cost_contribution = if required_value > nums[i] {
            required_value - nums[i]
        } else {
            0
        };

        cost_a += cost_contribution;
        i += 2;
    }

    // Calculate cost for Sequence B: {2, 4, 6, ...}
    let mut cost_b: i64 = 0;
    let mut i = 2;
    while i <= n - 2 {
        // Required value R_i must be strictly greater than both neighbors.
        let neighbors_max = nums[i - 1].max(nums[i + 1]);
        let required_value = neighbors_max + 1;

        let cost_contribution = if required_value > nums[i] {
            required_value - nums[i]
        } else {
            0
        };

        cost_b += cost_contribution;
        i += 2;
    }

    // Return the minimum cost required to achieve the maximum number of peaks.
    cost_a.min(cost_b)
}

